import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/Profile.css';

function Profile() {
  const navigate = useNavigate();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [userData, setUserData] = useState({
    name: '',
    age: '',
    sex: '',
    smoking: '',
    allergy: ''
  });
  const [originalUserData, setOriginalUserData] = useState({});
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [email, setEmail] = useState('');

  useEffect(() => {
    fetchUserData();
  }, []);

  const fetchUserData = async () => {
    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    try {
      setIsLoading(true);
      const response = await fetch(`http://localhost:5000/api/user-data/${user_id}`);
      if (!response.ok) {
        throw new Error('Failed to fetch user data');
      }
      const data = await response.json();
      setUserData(data);
      setOriginalUserData(data);

      // Fetch the email separately
      const emailResponse = await fetch(`http://localhost:5000/api/user-email/${user_id}`);
      if (!emailResponse.ok) {
        throw new Error('Failed to fetch user email');
      }
      const emailData = await emailResponse.json();
      setEmail(emailData.email);
    } catch (error) {
      console.error('Error fetching user data:', error);
      setError('Failed to load user data');
    } finally {
      setIsLoading(false);
    }
  };

  // Update form data when user inputs values
  const handleChange = (e) => {
    const { name, value } = e.target;
    setUserData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  // Submit form data to update user information
  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    // Validate data if needed
    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    try {
      const response = await fetch(`http://localhost:5000/api/update-user/${user_id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(userData),
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'Failed to update profile');
      }

      setSuccess('Profile updated successfully');
      setOriginalUserData({ ...userData });
      setTimeout(() => setSuccess(''), 3000);
    } catch (err) {
      console.error('Error updating profile:', err);
      setError(err.message || 'Failed to update profile');
    }
  };

  // Check if user has made changes to the form
  const hasChanges = () => {
    return (
      originalUserData.name !== userData.name ||
      originalUserData.age !== userData.age ||
      originalUserData.sex !== userData.sex ||
      originalUserData.smoking !== userData.smoking ||
      originalUserData.allergy !== userData.allergy
    );
  };

  const handleLogout = () => {
    localStorage.removeItem('user_id');
    navigate('/');
  };

  const toggleSidebar = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  return (
    <div className={`profile-container ${isSidebarOpen ? 'sidebar-open' : ''}`}>
      <div className="top-bar">
        <div className="top-center">
          <h1>Asthma Monitoring</h1>
        </div>
        <div className="nav-buttons">
          <button onClick={() => navigate('/dashboard')} className="dashboard-button">
            Dashboard
          </button>
          <button onClick={handleLogout} className="logout-button">
            Logout
          </button>
        </div>
      </div>

      <div className="profile-content">
        <h2>Profile Settings</h2>
        {isLoading ? (
          <p>Loading user data...</p>
        ) : error ? (
          <div className="error-message">{error}</div>
        ) : (
          <>
            {success && <div className="success-message">{success}</div>}
            <form className="profile-form" onSubmit={handleSubmit}>
              <div className="form-group">
                <input
                  type="text"
                  id="email"
                  value={email}
                  disabled
                  placeholder=" "
                />
                <label htmlFor="email">Email</label>
              </div>
              <div className="form-group">
                <input
                  type="text"
                  id="name"
                  name="name"
                  value={userData.name}
                  onChange={handleChange}
                  required
                  placeholder=" "
                />
                <label htmlFor="name">Name</label>
              </div>
              <div className="form-group">
                <input
                  type="number"
                  id="age"
                  name="age"
                  value={userData.age}
                  onChange={handleChange}
                  required
                  placeholder=" "
                />
                <label htmlFor="age">Age</label>
              </div>
              <div className="form-group">
                <label htmlFor="sex">Gender</label>
                <select
                  id="sex"
                  name="sex"
                  value={userData.sex}
                  onChange={handleChange}
                  required
                >
                  <option value="">Select Gender</option>
                  <option value="male">Male</option>
                  <option value="female">Female</option>
                </select>
              </div>
              <div className="form-group">
                <label className="radio-label">Smoking Status</label>
                <div className="radio-group">
                  <label>
                    <input
                      type="radio"
                      name="smoking"
                      value="yes"
                      checked={userData.smoking === 'yes'}
                      onChange={handleChange}
                      required
                    />
                    Yes
                  </label>
                  <label>
                    <input
                      type="radio"
                      name="smoking"
                      value="no"
                      checked={userData.smoking === 'no'}
                      onChange={handleChange}
                    />
                    No
                  </label>
                </div>
              </div>
              <div className="form-group">
                <input
                  type="text"
                  id="allergy"
                  name="allergy"
                  value={userData.allergy}
                  onChange={handleChange}
                  required
                  placeholder=" "
                />
                <label htmlFor="allergy">Allergies</label>
              </div>
              <button 
                type="submit" 
                className="save-button"
                disabled={!hasChanges()}
              >
                Save Changes
              </button>
            </form>
          </>
        )}
      </div>


      <div className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
         <h2>Menu</h2>
        </div>
        <nav className="sidebar-nav">
          <button onClick={() => navigate('/dashboard')}>
            Home
          </button>
          <button onClick={() => navigate('/recording-indicators')}>
            Recording Indicators
          </button>
          <button onClick={() => navigate('/exacerbation-forecast')}>
            Exacerbation Forecast
          </button>
          <button onClick={() => navigate('/graphs-of-changes')}>
            Graphs of Changes
          </button>
          <button onClick={() => navigate('/medication-diary')}>
            Medication Diary
          </button>
        </nav>
      </div>
      <div className="floating-menu-button" onClick={toggleSidebar}>
        <span></span>
        <span></span>
        <span></span>
      </div>
    </div>

  );

}

export default Profile;
